// ============================================================
// Logging
// ============================================================
app.use(morgan(':method :url :status :res[content-length] - :response-time ms - Origin: :req[origin]'));

// ============================================================
// Apply CORS middleware globally (before all routes)
// ============================================================
app.use(corsMiddleware);

// ============================================================
// Parse JSON and URL-encoded bodies
// ============================================================
app.use(express.json({ limit: '10mb' }));
app.use(express.urlencoded({ extended: true, limit: '10mb' }));

// ============================================================
// Request ID middleware for tracing
// ============================================================
app.use((req, res, next) => {
  const requestId = req.headers['x-request-id'] || generateRequestId();
  req.requestId = requestId;
  res.setHeader('X-Request-ID', requestId);
  next();
});

function generateRequestId() {
  return `${Date.now()}-${Math.random().toString(36).substring(2, 11)}`;
}

// ============================================================
// Rate Limiting
// ============================================================
const globalLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 1000,
  message: {
    error: 'Too many requests',
    message: 'Rate limit exceeded. Please try again later.',
  },
  standardHeaders: true,
  legacyHeaders: false,
});

app.use(globalLimiter);

// ============================================================
// Service Registry - Define backend microservices
// ============================================================
const SERVICES = {
  users: {
    target: process.env.USERS_SERVICE_URL || 'http://localhost:4001',
    pathRewrite: { '^/api/users': '/users' },
    description: 'User management service',
  },
  products: {
    target: process.env.PRODUCTS_SERVICE_URL || 'http://localhost:4002',
    pathRewrite: { '^/api/products': '/products' },
    description: 'Product catalog service',
  },
  orders: {
    target: process.env.ORDERS_SERVICE_URL || 'http://localhost:4003',
    pathRewrite: { '^/api/orders': '/orders' },
    description: 'Order management service',
  },
  auth: {
    target: process.env.AUTH_SERVICE_URL || 'http://localhost:4004',
    pathRewrite: { '^/api/auth': '/auth' },
    description: 'Authentication service',
  },
  notifications: {
    target: process.env.NOTIFICATIONS_SERVICE_URL || 'http://localhost:4005',
    pathRewrite: { '^/api/notifications': '/notifications' },
    description: 'Notification service',
  },
};

// ============================================================
// Health check endpoint
// ============================================================
app.get('/health', (req, res) => {
  res.json({
    status: 'healthy',
    timestamp: new Date().toISOString(),
    uptime: process.uptime(),
    services: Object.entries(SERVICES).map(([name, config]) => ({
      name,
      target: config.target,
      description: config.description,
    })),
  });
});

// ============================================================
// Service discovery endpoint
// ============================================================
app.get('/api', (req, res) => {
  res.json({
    message: 'API Gateway',
    version: '1.0.0',
    endpoints: Object.entries(SERVICES).map(([name, config]) => ({
      service: name,
      path: `/api/${name}`,
      description: config.description,
    })),
    cors: {
      allowedOrigins: '*',
      allowedMethods: 'GET, POST, PUT, PATCH, DELETE, OPTIONS, HEAD',
      note: 'All origins are allowed. All HTTP methods and common headers are supported.',
    },
  });
});

// ============================================================
// Proxy middleware factory
// ============================================================
function createServiceProxy(serviceName, serviceConfig) {
  return createProxyMiddleware({
    target: serviceConfig.target,
    changeOrigin: true,
    pathRewrite: serviceConfig.pathRewrite,
    timeout: 30000,
    proxyTimeout: 30000,

    on: {
      proxyReq: (proxyReq, req) => {
        // Forward request ID to backend services
        if (req.requestId) {
          proxyReq.setHeader('X-Request-ID', req.requestId);
        }
        // Forward the original client IP
        proxyReq.setHeader('X-Forwarded-For', req.ip);
        proxyReq.setHeader('X-Forwarded-Host', req.hostname);
        proxyReq.setHeader('X-Gateway-Service', serviceName);

        console.log(`[PROXY] ${req.method} ${req.originalUrl} -> ${serviceConfig.target}${req.url}`);
      },

      proxyRes: (proxyRes, req) => {
        // Remove any CORS headers set by backend services to avoid conflicts
        delete proxyRes.headers['access-control-allow-origin'];
        delete proxyRes.headers['access-control-allow-methods'];
        delete proxyRes.headers['access-control-allow-headers'];
        delete proxyRes.headers['access-control-allow-credentials'];

        console.log(`[PROXY RESPONSE] ${req.method} ${req.originalUrl} -> ${proxyRes.statusCode}`);
      },

      error: (err, req, res) => {
        console.error(`[PROXY ERROR] ${serviceName}: ${err.message}`);

        if (!res.headersSent) {
          res.status(502).json({
            error: 'Bad Gateway',
            message: `Service "${serviceName}" is unavailable`,
            service: serviceName,
            requestId: req.requestId,
            timestamp: new Date().toISOString(),
          });
        }
      },
    },
  });
}

// ============================================================
// Register proxy routes for each service
// ============================================================
Object.entries(SERVICES).forEach(([serviceName, serviceConfig]) => {
  const proxyPath = `/api/${serviceName}`;
  console.log(`[GATEWAY] Registering route: ${proxyPath} -> ${serviceConfig.target}`);
  app.use(proxyPath, createServiceProxy(serviceName, serviceConfig));
});

// ============================================================
// Mock endpoints for testing without backend services
// ============================================================
app.get('/api/test/echo', (req, res) => {
  res.json({
    message: 'CORS echo test',
    method: req.method,
    headers: {
      origin: req.headers.origin || 'no origin header',
      host: req.headers.host,
      'user-agent': req.headers['user-agent'],
      authorization: req.headers.authorization ? '[PRESENT]' : '[NOT SET]',
    },
    query: req.query,
    requestId: req.requestId,
    timestamp: new Date().toISOString(),
    cors: {
      'Access-Control-Allow-Origin': res.getHeader('Access-Control-Allow-Origin'),
    },
  });
});

app.post('/api/test/echo', (req, res) => {
  res.json({
    message: 'POST echo test',
    method: req.method,
    body: req.body,
    contentType: req.headers['content-type'],
    requestId: req.requestId,
    timestamp: new Date().toISOString(),
  });
});

// ============================================================
// 404 handler for unmatched routes
// ============================================================
app.use((req, res) => {
  res.status(404).json({
    error: 'Not Found',
    message: `Route ${req.method} ${req.originalUrl} does not exist`,
    availableEndpoints: [
      'GET  /health',
      'GET  /api',
      'GET  /api/test/echo',
      'POST /api/test/echo',
      ...Object.keys(SERVICES).map(s => `*    /api/${s}/*`),
    ],
    requestId: req.requestId,
    timestamp: new Date().toISOString(),
  });
});

// ============================================================
// Global error handler
// ============================================================
app.use((err, req, res, _next) => {
  console.error(`[ERROR] ${err.stack || err.message}`);

  res.status(err.status || 500).json({
    error: 'Internal Server Error',
    message: process.env.NODE_ENV === 'production'
      ? 'An unexpected error occurred'
      : err.message,
    requestId: req.requestId,
    timestamp: new Date().toISOString(),
  });
});

// ============================================================
// Start the server
// ============================================================
app.listen(PORT, () => {
  console.log('=========================================');
  console.log(`  API Gateway running on port ${PORT}`);
  console.log('=========================================');
  console.log(`  CORS: Access-Control-Allow-Origin: *`);
  console.log(`  Environment: ${process.env.NODE_ENV || 'development'}`);
  console.log('');
  console.log('  Registered services:');
  Object.entries(SERVICES).forEach(([name, config]) => {
    console.log(`    /api/${name} -> ${config.target}`);
  });
  console.log('');
  console.log('  Test endpoints:');
  console.log(`    GET  http://localhost:${PORT}/health`);
  console.log(`    GET  http://localhost:${PORT}/api`);
  console.log(`    GET  http://localhost:${PORT}/api/test/echo`);
  console.log(`    POST http://localhost:${PORT}/api/test/echo`);
  console.log('=========================================');
});

module.exports = app;